nta.declaration:
// Channels for synchronization between Heart, Ventricle controller, and Observer
//chan VSense, VPace;
broadcast chan VSense;   // intrinsic ventricular sense
broadcast chan VPace;    // ventricular pace

// Timing Parameters from the project specs (converted from bpm to milliseconds)
// Formula: Interval (ms) = 60,000 / Rate (bpm)

// --- Timing Parameters from project specs ---
//Given Constants: LRL = 40 bpm, URL = 180 bpm, HRL = 37.5 bpm, VRP = 150 ms
const int LRI = 1500; // Lower Rate Limit Interval (LRI) = 60,000/LowerRateLimit = 1500 ms/beat
const int URI = 333;  // Upper Rate Limit Interval (URI) = 60,000/UpperRateLimit = 333 ms/beat
const int HRI = 1600; // Hysteresis Rate Limit Interval (HRI) = 60,000/HysteresisRateLimit = 1600 ms/beat
const int VRP = 150;  // Ventricular Refractory Period (ms) - given constant

template.declaration:
clock x;          // Tracks time since last ventricular event
int RI = LRI;     // Current pacing interval (starts at LRI)

// Hysteresis / pacing control variables
bool hp = false;  // Hysteresis pacing enable flag
bool hpEnable = false;
bool started = false;
